def gen(rng, size):
    import random
    # generate a valid time then randomly replace some digits with '?'
    h = rng.randint(0, 11)
    m = rng.randint(0, 59)
    s = list(f'{h:02d}:{m:02d}')
    for i in [0, 1, 3, 4]:
        if rng.random() < 0.5:
            s[i] = '?'
    return [''.join(s)]

