class Solution:
    def findLatestTime(self, s: str) -> str:
        best = '00:00'
        for h in range(12):
            for m in range(60):
                t = f'{h:02d}:{m:02d}'
                ok = all(s[i] == '?' or s[i] == t[i] for i in range(5))
                if ok and t >= best:
                    best = t
        return best

