class Solution:
    def findLatestTime(self, s: str) -> str:
        a = list(s)
        # position 0: hour tens
        if a[0] == '?':
            # if hour unit is already fixed, determine max tens
            # if unit <= '1' or unit is '?', tens can be '1'; else must be '0'
            a[0] = '1' if (a[1] == '?' or a[1] <= '1') else '0'
        # position 1: hour unit
        if a[1] == '?':
            # max unit depends on tens digit
            a[1] = '1' if a[0] == '1' else '9'
        # position 3: minute tens
        if a[3] == '?':
            a[3] = '5'
        # position 4: minute units
        if a[4] == '?':
            a[4] = '9'
        return ''.join(a)
